extra.modelCss:
/* Imagens responsivas: padrão base */

img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* Card com imagem cortada bonita */
.card {
  border: 1px solid #ddd;
  border-radius: 14px;
  overflow: hidden;
}

.card .media img {
  width: 100%;
  height: 180px;
  object-fit: cover;
}

/* Logo: não cortar */
.logo {
  width: 140px;
  height: 48px;
  object-fit: contain;
}
